import java.util.concurrent.locks.ReentrantLock;

import static org.junit.jupiter.api.Assertions.*;
public class Parser_parseInput_1_Test {

    @Test
    @DisplayName("parseInput(Reader, baseUri) propagates runtime exceptions thrown by TreeBuilder.parse and still releases lock")
    public void test_TC07() throws Exception {
        // Setup stub TreeBuilder that always throws IllegalStateException in parse()
        TreeBuilder stubBuilder = new TreeBuilder() {
            @Override
            public Document parse(Reader in, String uri, Parser parser) {
                throw new IllegalStateException("fail-parse");
            }

            @Override
            public void process(Token token) {} // Implementing the abstract method

            @Override
            public TreeBuilder newInstance() { return this; }
            @Override
            public ParseSettings defaultSettings() { return ParseSettings.preserveCase(); } // Correct constructor
            @Override
            public TagSet defaultTagSet() { return TagSet.Html(); }
        };
        Parser parser = new Parser(stubBuilder);
        Reader reader = new StringReader("<html></html>");
        // Invoke and assert exception propagation
        IllegalStateException thrown = assertThrows(IllegalStateException.class, () ->
                parser.parseInput(reader, "http://example.com"),
            "Expected parseInput to throw the stubbed IllegalStateException");
        assertEquals("fail-parse", thrown.getMessage());

        // Reflectively verify that the lock is released after exception
        Field lockField = Parser.class.getDeclaredField("lock");
        lockField.setAccessible(true);
        ReentrantLock lock = (ReentrantLock) lockField.get(parser);
        assertFalse(lock.isLocked(), "Lock should be released even when parse throws");
    }

    @Test
    @DisplayName("parseInput(String, null) using String overload throws NullPointerException inside TreeBuilder.parse")
    public void test_TC08() {
        // Using real HtmlTreeBuilder; passing null baseUri triggers NPE in underlying parse()
        Parser parser = new Parser(new HtmlTreeBuilder());
        String html = "<div>test</div>";
        String baseUri = null;
        // The overload should delegate to parseInput(Reader, String) and lead to NPE
        assertThrows(NullPointerException.class,
            () -> parser.parseInput(html, baseUri),
            "Expected NullPointerException when baseUri is null");
    }
}
